@jagerman thanks for the detailed examples. What I need is described here: http://stackoverflow.com/questions/27488096/boost-python-raw-function-method  In boost python a raw function (any number of arguments) is combined with a static function that carries "self" in args[0], to give the impression in Python that it's a similar call to a "non-static" member function. I tried this below

`struct Test {
    Test(int v) : value{v} {}
    int value;
   **void SetParameters( py::args args, py::dict kargs ){  ///do things with args and kargs }**
};

PYBIND11_PLUGIN(mytest) {
    py::module m("mytest");

    py::class_<Test>(m, "Test")
        .def(py::init<int>())
        .def_readwrite("value", &Test::value)
        .def_static("static_func_pre21", [](py::args args) {
            Test &object = py::cast<Test &>(args[0]);
            return object.value;
        })
        .def_static("static_func_new", [](Test &object, py::args more) {
            return object.value;
        })
        .def("nonstatic_method", [](Test &self, py::args more) {
            return self.value;
        })
        .def("member_function", &SetParameters )
        ;

